def make_verb(t):
    id_, eng, msa_f, msa_t, root, msa_ex, lev_f, lev_t, lev_n, lev_ex, tags, rank = t
    return {
        "id": id_, "type": "verb", "english": eng,
        "msa": {"form": msa_f, "translit": msa_t, "root": root, "example": msa_ex},
        "lev": {"form": lev_f, "translit": lev_t, "notes": lev_n, "example": lev_ex},
        "tags": tags, "frequency_rank": rank
    }

def make_noun(t):
    id_, eng, msa_f, msa_t, root, msa_ex, lev_f, lev_t, lev_n, lev_ex, tags, rank = t
    return {
        "id": id_, "type": "noun", "english": eng,
        "msa": {"form": msa_f, "translit": msa_t, "root": root, "example": msa_ex},
        "lev": {"form": lev_f, "translit": lev_t, "notes": lev_n, "example": lev_ex},
        "tags": tags, "frequency_rank": rank
    }

data = {
    "_meta": {
        "description": "Arabic DrillForge vocabulary. Edit items below. Fields: id (unique), type (verb|noun), english, msa/lev objects, tags array, frequency_rank (lower=higher frequency).",
        "version": "1.0",
        "counts": {"verbs": len(VERBS), "nouns": len(NOUNS)}
    },
    "items": [make_verb(v) for v in VERBS] + [make_noun(n) for n in NOUNS]
}

with open("vocab.json", "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print(f"Generated {len(data['items'])} items")